function attendeeLabel(attendee){return attendee.name?`${attendee.name} <${attendee.email}>`:attendee.email;}
function eventAttendeesFromForm(source){const existing=new Map((source?.attendees||[]).map(attendee=>[attendee.email.toLocaleLowerCase(),attendee]));return String(document.getElementById('eventAttendees').value||'').split(/\n/).map(value=>value.trim()).filter(Boolean).map(value=>{const match=value.match(/^(.*?)\s*<([^<>]+)>$/),email=(match?.[2]||value).trim(),previous=existing.get(email.toLocaleLowerCase());return{email,name:match?.[1]?.trim()||previous?.name||null,role:previous?.role||'REQ-PARTICIPANT',partstat:previous?.partstat||'NEEDS-ACTION',rsvp:previous?.rsvp??true};});}
function eventInputFromForm(source){const allDay=document.getElementById('eventAllDay').checked,rruleMode=document.getElementById('eventRecurrence').value;return{summary:document.getElementById('eventSummary').value.trim(),description:document.getElementById('eventDescription').value.trim()||null,location:document.getElementById('eventLocation').value.trim()||null,dtstart:remoteDateValue(document.getElementById('eventStart').value,allDay),dtend:document.getElementById('eventEnd').value?remoteDateValue(document.getElementById('eventEnd').value,allDay):null,all_day:allDay,attendees:eventAttendeesFromForm(source),alarms:eventLineValues(document.getElementById('eventAlarms').value).map(Number).filter(value=>Number.isFinite(value)&&value>=0).map(trigger_minutes=>{const previous=(source?.alarms||[]).find(alarm=>alarm.trigger_minutes===trigger_minutes);return{trigger_minutes,action:previous?.action||'DISPLAY'};}),rrule:rruleMode==='custom'?document.getElementById('eventRrule').value.trim()||null:rruleMode||null,recurrence_id:source?.recurrence_id||null,exdates:eventLineValues(document.getElementById('eventExdates').value).join(',')||null,rdates:eventLineValues(document.getElementById('eventRdates').value).join(',')||null,timezone:document.getElementById('eventTimezone').value.trim()||null,transp:document.getElementById('eventTransp').value||null,class:document.getElementById('eventClass').value||null,categories:eventLineValues(document.getElementById('eventCategories').value),url:document.getElementById('eventUrl').value.trim()||null,organizer:document.getElementById('eventOrganizer').value.trim()||null,sequence:Number(source?.sequence||0)};}
function eventInputFromModel(source,dtstart,dtend){return{summary:source.summary,description:source.description||null,location:source.location||null,dtstart,dtend,all_day:Boolean(source.all_day),attendees:source.attendees||[],alarms:source.alarms||[],rrule:source.rrule||null,recurrence_id:source.recurrence_id||null,exdates:source.exdates||null,rdates:source.rdates||null,timezone:source.timezone||null,transp:source.transp||null,class:source.class||null,categories:source.categories||[],url:source.url||null,organizer:source.organizer||null,sequence:Number(source.sequence||0)};}
function setEventRecurrenceMode(rrule){const standard=['FREQ=DAILY','FREQ=WEEKLY','FREQ=MONTHLY','FREQ=YEARLY'],mode=!rrule?'':standard.includes(rrule)?rrule:'custom';document.getElementById('eventRecurrence').value=mode;document.getElementById('eventRrule').value=rrule||'';document.querySelector('.event-rrule-custom').classList.toggle('hidden',mode!=='custom');}
document.getElementById('eventRecurrence').onchange=event=>document.querySelector('.event-rrule-custom').classList.toggle('hidden',event.target.value!=='custom');
function setAuxMode(mode){const isEvent=mode==='event';eventForm.classList.toggle('hidden',!isEvent);contactForm.classList.toggle('hidden',isEvent);document.getElementById('auxTitle').textContent=isEvent?(editingEvent?L('Изменить событие / задачу','Edit event / task'):L('Новое событие / задача','New event / task')):(editingContact?L('Изменить контакт','Edit contact'):L('Новый контакт','New contact'));document.getElementById('auxIcon').innerHTML=isEvent?ic.cal:ic.people;}
function openEventEditor(event=null){editingEvent=event;editingContact=null;setAuxMode('event');fillAccountSelect(document.getElementById('eventAccount'),event?coreCalendarData.calendars.find(calendar=>calendar.id===event.calendar_id)?.account_id:coreAccounts[0]?.id);fillCalendarSelect(document.getElementById('eventAccount').value,event?.calendar_id);document.getElementById('eventAccount').disabled=Boolean(event);document.getElementById('eventCalendar').disabled=Boolean(event);document.getElementById('eventSummary').value=event?.summary||'';const start=event?.dtstart?localDateValue(event.dtstart):localDateValue(new Date(Math.ceil(Date.now()/1800000)*1800000).toISOString());document.getElementById('eventStart').value=start;document.getElementById('eventEnd').value=event?.dtend?localDateValue(event.dtend):localDateValue(new Date(new Date(start).getTime()+3600000).toISOString());document.getElementById('eventAllDay').checked=Boolean(event?.all_day)||/^\d{4}-\d{2}-\d{2}$/.test(event?.dtstart||'')||/^\d{8}$/.test(event?.dtstart||'');document.getElementById('eventLocation').value=event?.location||'';document.getElementById('eventDescription').value=event?.description||'';setEventRecurrenceMode(event?.rrule);document.getElementById('eventExdates').value=String(event?.exdates||'').split(',').join('\n');document.getElementById('eventRdates').value=String(event?.rdates||'').split(',').join('\n');document.getElementById('eventAttendees').value=(event?.attendees||[]).map(attendeeLabel).join('\n');document.getElementById('eventAlarms').value=(event?.alarms||[]).map(alarm=>alarm.trigger_minutes).join('\n');document.getElementById('eventOrganizer').value=event?.organizer||'';document.getElementById('eventTimezone').value=event?.timezone||Intl.DateTimeFormat().resolvedOptions().timeZone||'';document.getElementById('eventTransp').value=event?.transp||'opaque';document.getElementById('eventClass').value=event?.class||'public';document.getElementById('eventCategories').value=(event?.categories||[]).join(', ');document.getElementById('eventUrl').value=event?.url||'';document.querySelector('.event-advanced').open=Boolean(event&&(event.rrule||event.exdates||event.rdates||event.attendees?.length||event.alarms?.length||event.organizer||event.categories?.length||event.url));document.getElementById('eventDelete').classList.toggle('hidden',!event);document.getElementById('eventStatus').textContent='';auxOverlay.classList.add('open');document.getElementById('eventSummary').focus();}
function openContactEditor(contact=null){editingContact=contact;editingEvent=null;setAuxMode('contact');fillAccountSelect(document.getElementById('contactAccount'),contact?.account_id||coreAccounts[0]?.id);document.getElementById('contactAccount').disabled=Boolean(contact);document.getElementById('contactDisplayName').value=contact?.display_name||'';document.getElementById('contactFirstName').value=contact?.first_name||'';document.getElementById('contactLastName').value=contact?.last_name||'';document.getElementById('contactOrganization').value=contact?.organization||'';document.getElementById('contactEmails').value=(contact?.emails||[]).map(item=>item.email).join('\n');document.getElementById('contactDelete').classList.toggle('hidden',!contact);document.getElementById('contactStatus').textContent='';auxOverlay.classList.add('open');document.getElementById('contactDisplayName').focus();}
document.getElementById('eventAccount').onchange=e=>fillCalendarSelect(e.target.value);
document.getElementById('newEventBtn').onclick=()=>openEventEditor();
document.getElementById('newContactBtn').onclick=()=>openContactEditor();
document.getElementById('auxClose').onclick=closeAuxEditor;document.getElementById('eventCancel').onclick=closeAuxEditor;document.getElementById('contactCancel').onclick=closeAuxEditor;
auxOverlay.addEventListener('click',event=>{if(event.target===auxOverlay)closeAuxEditor();});
eventForm.onsubmit=async event=>{event.preventDefault();const status=document.getElementById('eventStatus'),input=eventInputFromForm(editingEvent);status.textContent=L('Сохраняю на сервере…','Saving to the server…');status.dataset.kind='';try{if(editingEvent)await window.tm.updateEvent(editingEvent.id,input);else await window.tm.createEvent(Number(document.getElementById('eventAccount').value),Number(document.getElementById('eventCalendar').value),input);await window.reloadCoreData();closeAuxEditor();showToast(L('Событие сохранено и синхронизировано','Event saved and synced'));}catch(error){status.textContent=String(error);status.dataset.kind='error';}};
document.getElementById('eventDelete').onclick=async()=>{if(!editingEvent||!confirm(L('Удалить событие или задачу на сервере?','Delete this event or task on the server?')))return;const status=document.getElementById('eventStatus');status.textContent=L('Удаляю…','Deleting…');try{await window.tm.deleteEvent(editingEvent.id);await window.reloadCoreData();closeAuxEditor();showToast(L('Удалено на сервере','Deleted on the server'));}catch(error){status.textContent=String(error);status.dataset.kind='error';}};
contactForm.onsubmit=async event=>{event.preventDefault();const status=document.getElementById('contactStatus'),input={display_name:document.getElementById('contactDisplayName').value.trim(),first_name:document.getElementById('contactFirstName').value.trim()||null,last_name:document.getElementById('contactLastName').value.trim()||null,organization:document.getElementById('contactOrganization').value.trim()||null,emails:document.getElementById('contactEmails').value.split(/[\n,;]/).map(value=>value.trim()).filter(Boolean)};status.textContent=L('Сохраняю на сервере…','Saving to the server…');status.dataset.kind='';try{if(editingContact)await window.tm.updateContact(editingContact.id,input);else await window.tm.createContact(Number(document.getElementById('contactAccount').value),input);await window.reloadCoreData();closeAuxEditor();showToast(L('Контакт сохранён и синхронизирован','Contact saved and synced'));}catch(error){status.textContent=String(error);status.dataset.kind='error';}};
document.getElementById('contactDelete').onclick=async()=>{if(!editingContact||!confirm(L('Удалить контакт на сервере?','Delete this contact on the server?')))return;const status=document.getElementById('contactStatus');status.textContent=L('Удаляю…','Deleting…');try{await window.tm.deleteContact(editingContact.id);await window.reloadCoreData();closeAuxEditor();showToast(L('Контакт удалён на сервере','Contact deleted on the server'));}catch(error){status.textContent=String(error);status.dataset.kind='error';}};
calSection.addEventListener('click',e=>{if(window.calendarDropJustHappened)return;const item=e.target.closest('.ev,.wk-ev');if(!item)return;e.stopPropagation();const event=coreCalendarData.events.find(value=>value.id===Number(item.dataset.eventId));if(event)openEventEditor(event);});
window.moveCalendarEvent=async(eventId,sourceValue,targetValue)=>{const source=coreCalendarData.events.find(value=>value.id===Number(eventId));if(!source)return;const parseTarget=value=>{const match=String(value).match(/^(\d{4})-(\d{2})-(\d{2})$/);return match?new Date(+match[1],+match[2]-1,+match[3]):parseDavDate(value);},sourceOccurrence=parseDavDate(sourceValue)||parseDavDate(source.dtstart),target=parseTarget(targetValue);if(!sourceOccurrence||!target)return;if(/^\d{4}-\d{2}-\d{2}$/.test(String(targetValue))&&!source.all_day)target.setHours(sourceOccurrence.getHours(),sourceOccurrence.getMinutes(),sourceOccurrence.getSeconds(),sourceOccurrence.getMilliseconds());const delta=target-sourceOccurrence,start=parseDavDate(source.dtstart),end=parseDavDate(source.dtend);if(!start)return;const movedStart=new Date(start.getTime()+delta),movedEnd=end?new Date(end.getTime()+delta):null,pad=value=>String(value).padStart(2,'0'),dateOnly=value=>`${value.getFullYear()}-${pad(value.getMonth()+1)}-${pad(value.getDate())}`,input=eventInputFromModel(source,source.all_day?dateOnly(movedStart):movedStart.toISOString(),movedEnd?(source.all_day?dateOnly(movedEnd):movedEnd.toISOString()):null);try{await window.tm.updateEvent(source.id,input);await window.reloadCoreData();showToast(L('Событие перенесено','Event moved'));}catch(error){showToast(error.message||String(error));}};

